import { Challenge } from './types';

// BUILDERS
const buildHTML = (data: any[]): Challenge[] => data.map(d => ({
  id: `html_${d.n}`,
  title: `Bài ${d.n}: ${d.title}`,
  difficulty: d.n > 18 ? 'Khó' : 'Trung bình',
  type: 'html',
  kind: 'lesson',
  description: d.desc,
  instructions: d.ins,
  hint: d.hint || 'Hãy xem kĩ yêu cầu nhé.',
  solution: d.sol,
  solutionExplanation: d.exp || 'Hoàn thành xuất sắc bộ cục HTML!',
  defaultCode: d.defCode || '<!-- Code ở đây -->\n',
  xpReward: 150 + (d.n * 10),
  validationSnippet: `const code = document.body.innerHTML.replace(/<!--[\\s\\S]*?-->/g, "").toLowerCase(); ${d.val}`,
}));

const buildCSS = (data: any[]): Challenge[] => data.map(d => {
  const reqProps = d.sol
    .replace(/^.*?\{/, '')
    .replace(/\}.*$/, '')
    .split(';')
    .map((s: string) => s.trim().toLowerCase())
    .filter(Boolean);

  return {
    id: `css_${d.n}`,
    title: `Bài ${d.n}: ${d.title}`,
    difficulty: d.n > 18 ? 'Khó' : 'Trung bình',
    type: 'css',
    kind: 'lesson',
    description: d.desc,
    instructions: d.ins,
    hint: d.hint || 'Chú ý cú pháp thuộc tính ;',
    solution: d.sol,
    solutionExplanation: d.exp || 'Giao diện mượt mà hơn hẳn!',
    defaultCode: `<div class="target">Giao diện thử nghiệm</div>\n<style>\n  .target {\n    ${d.defCode || ''}\n  }\n</style>`,
    xpReward: 150 + (d.n * 10),
    validationSnippet: `
      const userStyle = (document.body.querySelector('style')?.textContent || '').replace(/\\s+/g, '').toLowerCase();
      const reqPairs = ${JSON.stringify(reqProps)}.map(s => s.replace(/\\s+/g, ''));
      const missing = reqPairs.some(pair => !userStyle.includes(pair));
      if (missing) return false;
      const el = document.querySelector('.target'); 
      if(!el) return false; 
      ${d.val}
    `
  };
});

const buildJS = (data: any[]): Challenge[] => data.map(d => ({
  id: `js_${d.n}`,
  title: `Bài ${d.n}: ${d.title}`,
  difficulty: d.n > 18 ? 'Khó' : 'Trung bình',
  type: 'js',
  kind: 'lesson',
  description: d.desc,
  instructions: d.ins,
  hint: d.hint || 'Code JS cần tính chính xác tuyệt đối.',
  solution: `<script>\n${d.sol}\n</script>`,
  solutionExplanation: d.exp || 'Logic rất sắc bén!',
  defaultCode: `<script>\n  ${d.defCode || '// Viết thuật toán vào đây'}\n</script>`,
  xpReward: 150 + (d.n * 10),
  validationSnippet: `const code = (document.body.querySelector("script")?.textContent || "").replace(/\\/\\/.*|\\/\\*[\\s\\S]*?\\*\\//g, ""); ${d.val}`,
}));


